1. using System.Text.RegularExpressions;
2. 
3. namespace Textualizer.Inflections;
4. 
5. /// <summary>
6. /// Manages a set of pluralization and singularization rules, along with uncountable
7. /// and irregular word lists, for transforming English words between their plural
8. /// and singular forms.
9. /// </summary>
10. public class WordVocabulary
11. {
12.     private readonly List<InflectionEntry> _plurals = [];
13.     private readonly List<InflectionEntry> _singulars = [];
14. 
15.     private readonly HashSet<string> _uncountables = new(StringComparer.OrdinalIgnoreCase);
16. 
17.     // Correct pattern: uses OrdinalIgnoreCase for the irregulars map
18.     private readonly Dictionary<string, string> _irregularPlurals =
19.         new(StringComparer.OrdinalIgnoreCase);
20.     private readonly Dictionary<string, string> _irregularSingulars =
21.         new(StringComparer.OrdinalIgnoreCase);
22. 
23.     /// <summary>
24.     /// Gets the number of pluralization rules currently registered.
25.     /// </summary>
26.     public int PluralRuleCount => _plurals.Count;
27. 
28.     /// <summary>
29.     /// Gets the number of singularization rules currently registered.
30.     /// </summary>
31.     public int SingularRuleCount => _singulars.Count;
32. 
33.     /// <summary>
34.     /// Gets the number of uncountable words registered.
35.     /// </summary>
36.     public int UncountableCount => _uncountables.Count;
37. 
38.     /// <summary>
39.     /// Adds a pluralization rule with the given regex pattern and replacement.
40.     /// </summary>
41.     /// <param name="pattern">A regex pattern that matches the singular form.</param>
42.     /// <param name="replacement">The replacement string for generating the plural form.</param>
43.     public void AddPlural(string pattern, string replacement)
44.     {
45.         _uncountables.Remove(pattern);
46.         _uncountables.Remove(replacement);
47.         _plurals.Add(new InflectionEntry(pattern, replacement));
48.     }
49. 
50.     /// <summary>
51.     /// Adds a singularization rule with the given regex pattern and replacement.
52.     /// </summary>
53.     /// <param name="pattern">A regex pattern that matches the plural form.</param>
54.     /// <param name="replacement">The replacement string for generating the singular form.</param>
55.     public void AddSingular(string pattern, string replacement)
56.     {
57.         _uncountables.Remove(pattern);
58.         _uncountables.Remove(replacement);
59.         _singulars.Add(new InflectionEntry(pattern, replacement));
60.     }
61. 
62.     /// <summary>
63.     /// Registers an irregular plural/singular pair (e.g., "person" / "people").
64.     /// </summary>
65.     /// <param name="singular">The singular form of the word.</param>
66.     /// <param name="plural">The plural form of the word.</param>
67.     public void AddIrregular(string singular, string plural)
68.     {
69.         ArgumentException.ThrowIfNullOrWhiteSpace(singular);
70.         ArgumentException.ThrowIfNullOrWhiteSpace(plural);
71. 
72.         _uncountables.Remove(singular);
73.         _uncountables.Remove(plural);
74.         _irregularPlurals[singular] = plural;
75.         _irregularSingulars[plural] = singular;
76.     }
77. 
78.     /// <summary>
79.     /// Marks a word as uncountable (e.g., "equipment", "information", "rice").
80.     /// Uncountable words are returned unchanged by both pluralization and singularization.
81.     /// </summary>
82.     /// <param name="word">The uncountable word to register.</param>
83.     public void AddUncountable(string word)
84.     {
85.         ArgumentException.ThrowIfNullOrWhiteSpace(word);
86.         _uncountables.Add(word.Trim());
87.     }
88. 
89.     /// <summary>
90.     /// Returns the plural form of the given word using registered rules.
91.     /// </summary>
92.     /// <param name="word">The word to pluralize.</param>
93.     /// <returns>The plural form of the word.</returns>
94.     public string Pluralize(string word)
95.     {
96.         if (string.IsNullOrWhiteSpace(word))
97.         {
98.             return word;
99.         }
100. 
101.         if (_uncountables.Contains(word))
102.         {
103.             return word;
104.         }
105. 
106.         if (_irregularPlurals.TryGetValue(word, out var irregularPlural))
107.         {
108.             return irregularPlural;
109.         }
110. 
111.         return ApplyRules(_plurals, word) ?? word;
112.     }
113. 
114.     /// <summary>
115.     /// Returns the singular form of the given word using registered rules.
116.     /// </summary>
117.     /// <param name="word">The word to singularize.</param>
118.     /// <returns>The singular form of the word.</returns>
119.     public string Singularize(string word)
120.     {
121.         if (string.IsNullOrWhiteSpace(word))
122.         {
123.             return word;
124.         }
125. 
126.         if (_uncountables.Contains(word))
127.         {
128.             return word;
129.         }
130. 
131.         if (_irregularSingulars.TryGetValue(word, out var irregularSingular))
132.         {
133.             return irregularSingular;
134.         }
135. 
136.         return ApplyRules(_singulars, word) ?? word;
137.     }
138. 
139.     /// <summary>
