141.     /// </summary>
142.     /// <param name="word">The word to check.</param>
143.     /// <returns>true if the word is uncountable; otherwise, false.</returns>
144.     public bool IsUncountable(string word) =>
145.         !string.IsNullOrWhiteSpace(word) && _uncountables.Contains(word.Trim());
