147.     private static string? ApplyRules(List<InflectionEntry> rules, string word)
148.     {
149.         for (var i = rules.Count - 1; i >= 0; i--)
150.         {
151.             var result = rules[i].Apply(word);
152.             if (result != null)
153.             {
154.                 return result;
155.             }
156.         }
157. 
158.         return null;
159.     }
