176.         {
177.             var match = _regex.Match(word);
178.             if (!match.Success)
179.             {
180.                 return null;
181.             }
182. 
183.             // Splice the replacement into the original word in a single pass,
184.             // avoiding a redundant second regex execution via Replace().
185.             return string.Concat(
186.                 word.AsSpan(0, match.Index),
187.                 match.Result(_replacement),
