193. /// <summary>
194. /// Provides default English inflection rules for pluralization and singularization.
195. /// </summary>
196. public static class DefaultInflections
197. {
198.     /// <summary>
199.     /// Loads the default English inflection rules into the given vocabulary.
200.     /// These rules cover common English pluralization patterns including
201.     /// regular plurals, -ies/-ves transformations, and Latin/Greek-origin words.
202.     /// </summary>
203.     /// <param name="vocabulary">The vocabulary to populate with default rules.</param>
204.     public static void Load(WordVocabulary vocabulary)
205.     {
206.         ArgumentNullException.ThrowIfNull(vocabulary);
207. 
